sql:
SELECT description, start_date
FROM prize_structures
ORDER BY start_date DESC;

SELECT SUM(prize_amount) AS total_prize_amount
FROM prize_claims
WHERE claim_status = 'pending';

SELECT p.prize_tier_id, AVG(p.prize_amount) AS average_prize_amount_per_tier
FROM prize_tiers p
GROUP BY p.prize_tier_id;

SELECT COUNT(*) 
FROM prize_payments 
WHERE payment_status = 'failed';

SELECT game_id, total_prize_amount
FROM game_stats
ORDER BY total_prize_amount DESC;

SELECT game_stat_id, SUM(total_prize_amount) AS total_prize_amount_sum
FROM game_stats
GROUP BY game_stat_id;

SELECT game_id, SUM(total_prize_amount) AS total_prize_amount
FROM game_stats
GROUP BY game_id;

SELECT AVG(prize_amount) AS average_claimed_amount
FROM prize_claims
WHERE claim_date BETWEEN date('now','-30 days') AND date('now');

SELECT payment_date, payment_status
FROM prize_payments
WHERE payment_status = 'successful';

SELECT COUNT(DISTINCT prize_claim_id) AS total_prize_claims
FROM prize_claims
WHERE claim_date BETWEEN '2022-01-01' AND '2022-12-31';

SELECT name, email
FROM winners
WHERE date_of_birth > '1990-01-01';

SELECT COUNT(winner_id) AS number_of_winners
FROM winners
WHERE prize_match_id = 1;

SELECT prize_claim_id, prize_amount
FROM prize_claims
WHERE prize_claim_id IN (0, 1);
